INSERT INTO public.photos VALUES (22320, 'Parque Pignatelli 1969', 'Imagen desde cierta altura del parque de Pignatelli, bastante remozado al comienzo de la dâ”śÂ®cada, lo que le dio un nuevo aire a esta veterana zona verde de la ciudad, durante muchas dâ”śÂ®cadas "el parque" de todos los barrios que le rodean. A la derecha, y en primer tâ”śÂ®rmino, la zona de atracciones infantiles. A continuaciâ”śâ”‚n, la espesa atalaya que bordea los depâ”śâ”‚sitos de agua. Al fondo, la torre con los restos de los italianos fascistas que murieron por el triunfo del fascismo espaâ”śâ–’ol. A la izquierda, el paseo de Cuâ”śÂ®llar bordea el parque, con la enorme sombra de los altos bloques que sustituyeron a las anteriores edificaciones del barrio "de los Chiflaos". Aâ”śâ•‘n quedaba alguna parcela por normalizar. La imagen se ha podido tomar desde la altura del reciente nâ”¬â•‘ 80 del paseo de Mola. Fuente: "Zaragoza viva" (1969)', 1969, 1969, 1969, 'Anos 60', 'UNIVERSIDAD', 41.63868300, -0.88600800, '0101000020E6100000DDD1FF722D5AECBF6EC1525DC0D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15870228181.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15870228181.webp', 'https://www.flickr.com/photos/zaragozaantigua/15870228181/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22321, 'P.â”¬â•‘ del General Mola 1969', 'Imagen del andador central del paseo de Mola ocupado por Cabezudos y marabunta infantil bajando hacia el Centro urbano. Un gigante se atisba al fondo, entre la foresta. La captura se ha realizado cuando la comitiva acaba de cruzar la avenida de Goya, y llega a la zona donde a la izquierda queda la calle de La Paz, y a la derecha, Alar del Rey. Precisamente eso permite una mâ”śÂˇnima visual, a la derecha, de dos de los elementos del paseo piqueteados pocos aâ”śâ–’os despuâ”śÂ®s, y sustituidos por asâ”śÂ®pticas y descontextualizadas moles de viviendas: el oblongo solar entre Alar del Rey y Goya, donde estuvo la fâ”śĂ­brica de Manuel Viâ”śâ–’ado hasta 1925, luego el Colegio de las Hermanas Carmelitas de la Caridad, hasta 1949, y luego la Academia preparatoria de acceso a la AGM "La Figuera", hasta 1971; y el hotelito de los Palomar, con jardâ”śÂˇn y estatua, que hacâ”śÂˇa esquina entre Mola y Goya (bâ”śĂ­rbara mezcolanza), a punto de ser derribado Fuente: "Zaragoza viva" (1969)', 1969, 1969, 1969, 'Anos 60', 'UNIVERSIDAD', 41.64258600, -0.88618800, '0101000020E6100000DA71C3EFA65BECBF096F0F4240D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15872039932.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15872039932.webp', 'https://www.flickr.com/photos/zaragozaantigua/15872039932/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22348, 'Parque Pignatelli 1961', 'El Parque de Pignatelli era veterana zona verde desde que en 1904 fuera aquâ”śÂˇ trasplantada la estatua del prâ”śâ”‚cer que le da nombre. La imagen ha sido realizada tras una reciente remodelaciâ”śâ”‚n y puesta a punto del parque, con bancos nuevos, farolas trasplantadas del Paseo Independencia (tras su conversiâ”śâ”‚n en autopista central), y una manita de pintura en los muros del terraplâ”śÂ®n sobre el que se encuentran los antiguos Depâ”śâ”‚sitos de agua. La chiquillerâ”śÂˇa y juventud de entonces recuerdan esta sencilla escultura asociada a una fuente del parque. Tras la reforma del Parque en 1986, fue hecha desaparecer. Fuente visual: foto de Josâ”śÂ® Marâ”śÂˇa Rey, en www.rafaelcastillejo.com/torrero.htm', 1961, 1961, 1961, 'Anos 60', 'UNIVERSIDAD', 41.63582000, -0.88515000, '0101000020E6100000A5BDC1172653ECBF4512BD8C62D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20320774121.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20320774121.webp', 'https://www.flickr.com/photos/zaragozaantigua/20320774121/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22411, 'Juan Pablo Bonet 1966', 'Imagen de los reciâ”śÂ®n inaugurados "Laboratorios ULTA", en la calle Juan Pablo Bonet, ya con el râ”śâ”‚tulo indicativo colocado en su sitio. Fuente visual: Gerardo Sancho Ramo, Archivo Pâ”śâ•‘blico Municipal.', 1966, 1966, 1966, 'Anos 60', 'UNIVERSIDAD', 41.63997500, -0.88735100, '0101000020E61000002A55A2EC2D65ECBFF9A067B3EAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24911502692.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24911502692.webp', 'https://www.flickr.com/photos/zaragozaantigua/24911502692/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22414, 'Parque de Pignatelli c.1963', 'Luminosa imagen del parque de Pignatelli tras su remodelaciâ”śâ”‚n de 1961, con la referencial estatua del prâ”śâ”‚cer que le dio nombre, tras su destierro de la plaza de Aragâ”śâ”‚n. Fuente: www.todocoleccion.net/', 1963, 1963, 1963, 'Anos 60', 'UNIVERSIDAD', 41.63686900, -0.88504400, '0101000020E61000003BAC70CB4752ECBF096B63EC84D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25347087749.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25347087749.webp', 'https://www.flickr.com/photos/zaragozaantigua/25347087749/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22432, 'P.â”¬â•‘ del General Mola 1967', 'Imagen de una unidad motor+remolque de la serie 100 en servicio en la lâ”śÂˇnea 5 del tranvâ”śÂˇa, "Torrero-Delicias", bajando por el paseo del general Mola en direcciâ”śâ”‚n al barrio de Delicias. La captura se ha realizado en el cruce del paseo con la avenida de Goya. Al fondo, el hotelito de la familia de Josâ”śÂ® Palomar esquinero entre ambos viales, poco antes de su demoliciâ”śâ”‚n. Detrâ”śĂ­s, emerge la cuadrangular torre del "Santuario de Nâ”¬Â¬ Sâ”¬Â¬ del Perpetuo Socorro". Fuente visual: Gerardo Sancho Ramo, AMZ.', 1967, 1967, 1967, 'Anos 60', 'UNIVERSIDAD', 41.64208400, -0.88620000, '0101000020E6100000EBE2361AC05BECBF76A4FACE2FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29617431453.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29617431453.webp', 'https://www.flickr.com/photos/zaragozaantigua/29617431453/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22496, 'Parque de Pignatelli c.1965', 'Colorista imagen capturada en el parque de Pignatelli junto al monumento dedicado al homâ”śâ”‚nimo prâ”śâ”‚cer ilustrado responsable, entre otras, de la magnâ”śÂˇfica empresa del Canal Imperial de Aragâ”śâ”‚n. Originalmente estuvo enclavado en la Glorieta a la que dio nombre, entre 1865 y 1904, cuando fue expulsada del centro urbano y reubicada en un secarral que, con el tiempo, se convertirâ”śÂˇa en frondoso parque urbano. El acuâ”śĂ­tico aspecto del entorno al monumento le fue conferido por una importante reforma del parque acometida en 1961, hasta que otra gran reforma llevada a cabo en 1985 le darâ”śÂˇa su actual aspecto', 1965, 1965, 1965, 'Anos 60', 'UNIVERSIDAD', 41.63688700, -0.88511800, '0101000020E6100000CD3AE3FBE252ECBFB01F628385D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48323107027.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48323107027.webp', 'https://www.flickr.com/photos/zaragozaantigua/48323107027/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22536, 'P.â”¬â•‘ del General Mola 1971', 'Para empezar, se trata de una imagen mediocre, tomada desde el paseo del General Mola. Estamos cerca del encuentro con el final del Camino de las Torres, donde avanzaba la erecciâ”śâ”‚n del proyecto de "Edificio Residencial" a la altura del nâ”śâ•‘mero 64 del Paseo. Uno mâ”śĂ­s entre las decenas y decenas de construcciones desarrollistas de la Zaragoza del momento. Destacar, tal vez, lo naâ”śÂ»f del dibujo del cartel publicitario, que representa un edificio postmoderno y funcional, absolutamente descontextualizado de su entorno, de 9 alturas mâ”śĂ­s bajos. La importancia de la imagen es lo que se atisba parcialmente a su derecha: el "hotelito" o vivienda que empezâ”śâ”‚ siendo el nâ”¬â•‘ 26 duplicado, y ahora era el nâ”¬â•‘ 62, aâ”śâ•‘n superviviente del burguâ”śÂ®s ensanche conformado por el antiguo paseo de Sagasta. Esta fue "Villa Dolores", la clâ”śÂˇnica del Doctor Arpal, edificio exento, de tres plantas, identificable por su airosa, lateral y semicircular galerâ”śÂˇa orientada hacia el sur. Tenâ”śÂˇa el preceptivo jardincillo de los nâ”śâ•‘meros pares del paseo, por donde el ingreso principal. Otro acceso trasero daba al camino del Sâ”śĂ­bado, que en este tramo hoy se denomina calle Maestro Marquina. Tantos y tan burgueses antecedentes no le evitaron el trance de la piqueta, y unos aâ”śâ–’os despuâ”śÂ®s de tomada la imagen en color fue derribado por el emprendedor Colmenero para ganar edificabilidad, altura y plusvalâ”śÂˇas. A los nuevos ricos de la ciudad les motivan mâ”śĂ­s otras cosas. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1971, 1971, 1971, 'Anos 70', 'UNIVERSIDAD', 41.64051100, -0.88657200, '0101000020E6100000F793313ECC5EECBF37DDB243FCD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14851750022.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14851750022.webp', 'https://www.flickr.com/photos/zaragozaantigua/14851750022/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22551, 'P.â”¬â•‘ del General Mola 1977', 'Airoso palacete que fuera de los Escoriaza-Averly en el nâ”¬â•‘ 32 del paseo, derribado sin contemplaciones, como muchos de sus compaâ”śâ–’eros, en la acera par del paseo de Sagasta de Zaragoza, con Cervantes. Poco le faltaba: la foto es de 1977 y en su lugar hay una mole monstruosa. Fuente visual: foto Josâ”śÂ® Monge, en www.rafaelcastillejo.com/', 1977, 1977, 1977, 'Anos 70', 'UNIVERSIDAD', 41.64380300, -0.88624000, '0101000020E610000079060DFD135CECBF8908FF2268D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15026608165.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15026608165.webp', 'https://www.flickr.com/photos/zaragozaantigua/15026608165/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22559, 'P.â”¬â•‘ del General Mola 1977', 'Fotografâ”śÂˇa de Câ”śÂ®sar Sâ”śĂ­nchez Vâ”śĂ­zquez. 1977. Imagen parcial del hotelito del Paseo de Sagasta nâ”¬â•‘ 52. Fue construido en 1919 por encargo de Luis Lâ”śâ”‚pez Ferrer al arquitecto Teodoro Râ”śÂˇos Balaguer, que lo diseâ”śâ–’â”śâ”‚ en lâ”śÂˇneas eclâ”śÂ®cticas. En 1961 su propietaria era Elena Valenzuela vendiâ”śâ”‚ el inmueble al Ministerio de la Vivienda y, posteriormente, al Ministerio de Cultura. Desaparecido por derribo a finales de los aâ”śâ–’os 90 del siglo XX.', 1977, 1977, 1977, 'Anos 70', 'UNIVERSIDAD', 41.64169800, -0.88655000, '0101000020E6100000029A081B9E5EECBF4DF4F92823D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15208824779.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15208824779.webp', 'https://www.flickr.com/photos/zaragozaantigua/15208824779/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22561, 'P.â”¬â•‘ del General Mola 1977', 'Fotografâ”śÂˇa de Câ”śÂ®sar Sâ”śĂ­nchez Vâ”śĂ­zquez. 1977. Imagen del edificio de Sagasta 37. Supervive, con una adiciâ”śâ”‚n construida en vertical sobre la galerâ”śÂˇa acristalada de la derecha. El edificio a su izquierda (Sagasta 35), no.', 1977, 1977, 1977, 'Anos 70', 'UNIVERSIDAD', 41.64116000, -0.88613700, '0101000020E610000052D158FB3B5BECBF6EC0E78711D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15208918499.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15208918499.webp', 'https://www.flickr.com/photos/zaragozaantigua/15208918499/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22562, 'P.â”¬â•‘ del General Mola 1977', 'Fotografâ”śÂˇa de Câ”śÂ®sar Sâ”śĂ­nchez Vâ”śĂ­zquez. 1977. Imagen del hotelito del Paseo de Sagasta 52 (desaparecido). Al fondo, la iglesia de Ntra. Sra. del Perpetuo Socorro. A su derecha, avanzada construcciâ”śâ”‚n de la mole de 9 alturas de Sagasta 50, sobre hotelito desaparecido. A su izquierda, las vallas anunciadoras de la inminente construcciâ”śâ”‚n "de esmerada calidad" del horror de 9 alturas que sustituyâ”śâ”‚ al reciâ”śÂ®n desaparecido hotelito de Emerenciano Garcâ”śÂˇa (Sagasta, 54).', 1977, 1977, 1977, 'Anos 70', 'UNIVERSIDAD', 41.64169800, -0.88655000, '0101000020E6100000029A081B9E5EECBF4DF4F92823D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15209597427.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15209597427.webp', 'https://www.flickr.com/photos/zaragozaantigua/15209597427/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22571, 'P.â”¬â•‘ del General Mola 1974', 'Sâ”śĂ­nchez Millâ”śĂ­n. 1974. Imagen de la vivienda modernista de Julio Juncosa en el paseo de Sagasta 11, proyectada por Josâ”śÂ® de Yarza en colaboraciâ”śâ”‚n con Ricardo Magdalena en 1903 y concluida en 1906. A pesar de que la foto estâ”śĂ­ tomada en la dâ”śÂ®cada de los setenta, donde la mortalidad de casas, hotelitos y demâ”śĂ­s residencias de principios del siglo XX, era muy alta, este edificio sobrevive. Su vecina de la izquierda, de la que apenas se ve un pedazo, ha sido deconstruida totalmente, y recrecida. Fuente visual: Revista "Triunfo" (1974)', 1974, 1974, 1974, 'Anos 70', 'UNIVERSIDAD', 41.64342300, -0.88583000, '0101000020E61000000D1AFA27B858ECBF423F53AF5BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15342538943.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15342538943.webp', 'https://www.flickr.com/photos/zaragozaantigua/15342538943/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22572, 'P.â”¬â•‘ del General Mola 1977', 'Fotografâ”śÂˇa de Câ”śÂ®sar Sâ”śĂ­nchez Vâ”śĂ­zquez. Imagen del edificio de Sagasta 40, esquina con la calle Zumalacâ”śĂ­rregui. Supervive, restaurado y limpio, y conserva su zona de acceso con plantas y verja. Las vallas de la derecha se corresponden con el solar sobre el que mâ”śĂ­s tarde se levantarâ”śĂ­ la mole de 9 alturas de Sagasta 32-38, previo piqueteo de los hotelitos de los nâ”śâ•‘meros 32, 34, 36 y 38 del Paseo.', 1977, 1977, 1977, 'Anos 70', 'UNIVERSIDAD', 41.64330900, -0.88634100, '0101000020E6100000725303CDE75CECBF7A1C06F357D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15395961155.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15395961155.webp', 'https://www.flickr.com/photos/zaragozaantigua/15395961155/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22587, 'Laboratorios Verkos 1977', 'En una familiar rebotica nacieron en 1918 los Laboratorios Verkos. En 1938 levantaron, con proyecto del arquitecto Teodoro Râ”śÂˇos Balaguer, un nuevo e interesante edificio en la calle Gil de Jasa nâ”¬â•‘ 16, esquina con calle Cervantes. Allâ”śÂˇ investigaron, probaron y produjeron los productos de la marca comercial "Kemphor", como su elixir bucal (desde 1940), y su pasta de dientes (aâ”śâ–’os 50), ademâ”śĂ­s de otros elementos secundarios. En 1976 abandonaron estas instalaciones, y se trasladaron a su actual ubicaciâ”śâ”‚n, en la carretera de Logroâ”śâ–’o, km. 20, al lado de Pinseque. En 1979 la piqueta derribâ”śâ”‚ el inmueble, y en su solar se levantaron las actuales viviendas. En la imagen el edificio de Laboratorio Verkos, en una captura realizada desde la calle Cervantes. Al fondo, tras el Huerva, los bloques de viviendas de la manzana entre Goya y Gran Vâ”śÂˇa. Fuente visual: "La evoluciâ”śâ”‚n urbana de Zaragoza al este del Huerva", Carmen Santos Vich, 1978.', 1977, 1977, 1977, 'Anos 70', 'UNIVERSIDAD', 41.64395000, -0.88680200, '0101000020E610000065E08096AE60ECBF2D211FF46CD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15725815116.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15725815116.webp', 'https://www.flickr.com/photos/zaragozaantigua/15725815116/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22602, 'Avenida de Goya 1973', 'Foto del reciente derribo del edificio de la avenida Goya 2, esquina con el paseo del General Mola (hoy Sagasta). A la izquierda, parroquia del Perpetuo Socorro. Fuente: Diario Amanecer, 21 de marzo de 1973.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.64264000, -0.88673500, '0101000020E610000072FE26142260ECBFFC8C0B0742D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18761537963.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18761537963.webp', 'https://www.flickr.com/photos/zaragozaantigua/18761537963/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22603, 'Avenida de Goya 1973', 'Foto Monge, 1973. Imagen tomada para noticiar con alborozo el inminente derribo del inmueble esquinero del paseo del General Mola con la avenida de Goya 2 (a la izquierda). Esta casa fue colegio de las Carmelitas de la Caridad entre 1925 y 1949 y luego academia La Figuera hasta 1971. Habâ”śÂˇa sido levantada sobre los terrenos de la fâ”śĂ­brica de râ”śâ”‚tulos esmaltados Viâ”śâ–’ado, sita allâ”śÂˇ entre 1902 y 1925. Fuente: Diario Amanecer, 16 de enero de 1973.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.64264000, -0.88673500, '0101000020E610000072FE26142260ECBFFC8C0B0742D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18782536894.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18782536894.webp', 'https://www.flickr.com/photos/zaragozaantigua/18782536894/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22652, 'P.â”¬â•‘ de Ruiseâ”śâ–’ores 1977', 'Imagen del que fuera hotelito de Raimundo Balet tras la parcelaciâ”śâ”‚n de un terreno inmediato a los depâ”śâ”‚sitos de agua de Pignatelli, en el nâ”¬â•‘ 15 (actual nâ”¬â•‘ 41) del paseo de Ruiseâ”śâ–’ores, en la primera dâ”śÂ®cada del siglo XX. Tenâ”śÂˇa como vecinos a los "hotelitos" de â”śĂĽngel Anâ”śâ”‚s o Villa Rosita (a la izquierda) y el de Sebastiâ”śĂ­n Rodrâ”śÂˇguez (a la derecha, fuera de plano), todos de singular y notable fâ”śĂ­brica, con entrada desde el paseo, y unas espaciosas traseras para jardines. Unos aâ”śâ–’os mâ”śĂ­s tarde los tres serâ”śÂˇan recompuestos en formas y maneras mâ”śĂ­s postmodernas, al gusto de las nuevas economâ”śÂˇas dirigentes. Fuente visual: "La evoluciâ”śâ”‚n urbana de Zaragoza al este del Huerva", Carmen Santos Vich, 1978.', 1977, 1977, 1977, 'Anos 70', 'UNIVERSIDAD', 41.63635700, -0.88902300, '0101000020E6100000B189CC5CE072ECBF53CA6B2574D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21200905842.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21200905842.webp', 'https://www.flickr.com/photos/zaragozaantigua/21200905842/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22653, 'Casa Palomar 1970', 'Entrada del hotelito de la familia de Josâ”śÂ® Palomar (construido en 1850), en la esquina del paseo del General Mola 50 con la Avenida Goya 1. Fue derribado poco despuâ”śÂ®s de esta captura fotogrâ”śĂ­fica.. Fuente visual: revista "Aragâ”śâ”‚n turâ”śÂˇstico y monumental" (1970).', 1970, 1970, 1970, 'Anos 70', 'UNIVERSIDAD', 41.64236500, -0.88654400, '0101000020E61000007AE1CE85915EECBF2A8C2D0439D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21305265178.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21305265178.webp', 'https://www.flickr.com/photos/zaragozaantigua/21305265178/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22681, '&quot;Rastro de Pignatelli&quot; 1973', 'La resaca de las fiestas mayores de 1973 incluyâ”śâ”‚ el anuncio de un proyecto "francamente avanzado" que, por supuesto, iba a influir poderosamente en el futuro de la ciudad: la realizaciâ”śâ”‚n de un "Rastro" en los antiguos depâ”śâ”‚sitos de agua de Pignatelli, algo que pondrâ”śÂˇa a Zaragoza a la altura de ciudades como Madrid, Parâ”śÂˇs, o Londres, al menos en este asunto. La propuesta suponâ”śÂˇa cubrir los antiguos depâ”śâ”‚sitos al aire, y convertirlos en ocho grandes pabellones permanentes que cobijarâ”śÂˇan docenas y docenas de tenderetes, a modo de galerâ”śÂˇas de artesanos y vendedores de antigâ”śâ•ťedades, cerâ”śĂ­mica, forja, libros de lance, pinturas, flores, et caetera. El entorno serâ”śÂˇa convenientemente embellecido con jardines de rocalla, â”śĂ­rboles (plâ”śĂ­tanos de sombra, chopos, cipreses), amâ”śÂ®n de florestas y rosales trepadores; muchos bancos para sentarse; varias fuentes de agua potable, y una grande ornamental; servicios pâ”śâ•‘blicos, y dos quioscos con bar, flanqueando una plataforma cubierta para banda de mâ”śâ•‘sica, o actuaciones teatrales. Los depâ”śâ”‚sitos subterrâ”śĂ­neos serâ”śÂˇan reconvertidos en permanente sala de exposiciones de artesanâ”śÂˇa. La realizaciâ”śâ”‚n de este proyecto tenâ”śÂˇa un coste estimado de diez millones de pesetas, aunque por diversas circunstancias no fue realizado, entrando a formar parte, por ello, en el poblado territorio onâ”śÂˇrico zaragozano, esas vastas geografâ”śÂˇas cohabitadas por los sueâ”śâ–’os y las pesadillas de la ciudad, en todas sus dimensiones. La imagen reproduce, coloreado, el proyectado "Rastro". Al sur, los accesos desde el parque de Pignatelli. A la derecha, los lâ”śÂˇmites recayentes al paseo de los Ruiseâ”śâ–’ores, A la izquierda, el muro separador con las traseras de Maestro Estremiana. Al norte, muro junto a la calle (sin salida) de Santiago Guallar. Fuente visual: "Heraldo de Aragâ”śâ”‚n". Cromatismo aâ”śâ–’adido por GAZA.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.63629500, -0.88602900, '0101000020E6100000BAD7497D595AECBFDDCD531D72D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26365421172.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26365421172.webp', 'https://www.flickr.com/photos/zaragozaantigua/26365421172/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22766, 'Alar del Rey 1972', 'Imagen bien poco postalera de la calle Alar del Rey, entre el primer tramo de la calle del Arzobispo Domâ”śÂ®nech, y el paseo del General Mola, al fondo, sometida a una intensa intervenciâ”śâ”‚n relacionada con la renovaciâ”śâ”‚n de la red de alcantarillado de la zona. A la izquierda, traseras de las parcelas 13 y 15 recayentes a la calle de Zumalacâ”śĂ­rregui, que perduran, oh sorpresa. Un poco mâ”śĂ­s adelante, colegio femenino Santo Tomâ”śĂ­s de Aquino instalado en la antigua "Villa Teresa", esquinera con Gil de Jasa. A la derecha, academia La Figuera, recientemente clausurada. Al fondo, el nâ”¬â•‘ 21 del paseo del General Mola, recayente a la calle de la Paz, y a su derecha, apenas visible, la clâ”śÂˇnica del doctor Bandragen. Fuente visual: AMZ.', 1972, 1972, 1972, 'Anos 70', 'UNIVERSIDAD', 41.64314100, -0.88788600, '0101000020E6100000B07092E68F69ECBFBEDBBC7152D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33229001000.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33229001000.webp', 'https://www.flickr.com/photos/zaragozaantigua/33229001000/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22808, 'Parque de Pignatelli 1973', 'Imagen capturada en el "mini-parque de atracciones" habilitado a la derecha de la entrada norte al parque de Pignatelli y recayente a la glorieta de Diego Velâ”śĂ­zquez. La escena se centra en la zona de camas elâ”śĂ­sticas donde los peques brincaban que te brincaban. Ademâ”śĂ­s, este recoleto recinto contaba tambiâ”śÂ®n con un singular circuito acuâ”śĂ­tico de barquitos y una zona de cochecitos de choque. Todo un oasis para la chiquillerâ”śÂˇa de los barrios limâ”śÂˇtrofes.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.63873100, -0.88634100, '0101000020E6100000725303CDE75CECBF7FF8F9EFC1D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51530365811.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51530365811.webp', 'https://www.flickr.com/photos/zaragozaantigua/51530365811/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22937, 'Gil de Jasa 1980', 'Acristaladas traseras de la casa del nâ”¬â•‘ 40 del paseo de Sagasta, diseâ”śâ–’ada en 1910 por Luis de la Figuera. Poco despuâ”śÂ®s de capturar esta imagen fue recrecida en una altura y esta parte, recayente a la calle de Antonio Gil de Jasa, serâ”śÂˇa remozada sustituyendo la quejumbrosa y provinciana solanera caracterâ”śÂˇstica de los hotelitos del antiguo paseo, por una mâ”śĂ­s moderna fachada compuesta por vanos y ladrillo caravista. A la izquierda, la calle de Tomâ”śĂ­s Zumalacâ”śĂ­rregui. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1980, 1980, 1980, 'Anos 80', 'UNIVERSIDAD', 41.64331900, -0.88654300, '0101000020E610000063EDEF6C8F5EECBF9DF2E84658D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32534749632.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32534749632.webp', 'https://www.flickr.com/photos/zaragozaantigua/32534749632/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22991, 'Parque Pignatelli aâ”śâ–’os 90', 'Vista del Parque Pignatelli de Zaragoza desde la torre de la iglesia de San Antonio. A su izquierda, los depâ”śâ”‚sitos de agua homâ”śâ”‚nimos aâ”śâ•‘n en funcionamiento en la â”śÂ®poca de la imagen.', 1990, 1990, 1999, 'Anos 90', 'UNIVERSIDAD', 41.63742900, -0.88528100, '0101000020E610000048A5D8D13854ECBFD042024697D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20985535940.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20985535940.webp', 'https://www.flickr.com/photos/zaragozaantigua/20985535940/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23038, 'Paseo de Sagasta 1990', 'Imagen capturada desde la altura del veterano inmueble del nâ”¬â•‘ 72 del paseo de Sagasta, con una buena vista del tramo de este paseo que confluye, en primer tâ”śÂ®rmino, con el arranque de la calle de Juan Pablo Bonet, hacia la izquierda, y el final del camino de las Torres, desde la derecha. La configuraciâ”śâ”‚n edilicia definitiva de esta zona del ensanche burguâ”śÂ®s de principios del siglo XX, se fue completando con nuevos inmuebles que desde la dâ”śÂ®cada de los aâ”śâ–’os 50 fueron sustituyendo las originales viviendas unifamiliares que determinaban el estilo y escala del paseo en la escena que la imagen representa. Aâ”śâ•‘n en los aâ”śâ–’os 90 hubo dos casos, uno relacionado con el "desatasque" del polâ”śÂ®mico edificio del emprendedor inmobiliario Colmenero, que construido en los aâ”śâ–’os 70 en el nâ”¬â•‘ 62, a la izquierda del paseo, estuvo en barbecho durante casi veinte aâ”śâ–’os hasta que finalmente fue legalmente ocupado. Y en la acera de enfrente, el veterano edificio del nâ”¬â•‘ 37 fue objeto de una importante rehabilitaciâ”śâ”‚n terminada casi al principio de esta dâ”śÂ®cada. A su izquierda, el nâ”¬â•‘ 35 serâ”śÂˇa finalmente remodelado aâ”śâ–’os despuâ”śÂ®s con proyecto de Josâ”śÂ® Manuel Pâ”śÂ®rez Latorre, ya en el principio de la siguiente dâ”śÂ®cada y siglo.', 1990, 1990, 1990, 'Anos 90', 'UNIVERSIDAD', 41.64039100, -0.88638400, '0101000020E6100000435376FA415DECBF8DD31055F8D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50376532331.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50376532331.webp', 'https://www.flickr.com/photos/zaragozaantigua/50376532331/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23434, 'Calle de Gil de Jasa 1969', 'Imagen de la antigua "Villa Teresa", singular casa de postâ”śÂˇn esquinera entre las calles de Gil de Jasa y de la Cadena y construida en bizarras formas neogâ”śâ”‚ticas en los albores del siglo XX, cuando aâ”śâ•‘n no era obligatorio presentar proyecto de obra ni planos ante el Ayuntamiento. Por ello, esta es una de las pocas referencias visuales de que este edificio fue una realidad, no una ensoâ”śâ–’aciâ”śâ”‚n. Desde el aâ”śâ–’o 1950 aquâ”śÂˇ estuvo establecido el Hogar-Residencia Femenino "Isabel de Aragâ”śâ”‚n" del Auxilio Social, con capacidad para cuarenta chicas que cursaban estudios de Bachiller, Magisterio, Filosofâ”śÂˇa y Letras... En el momento de capturar esta fotografâ”śÂˇa la casa estaba alquilada por la familia propietaria (Delgado Yarza) al colegio femenino de bachillerado "Santo Tomâ”śĂ­s de Aquino", sito en la calle Gil de Jasa nâ”¬â•‘ 24, esquina con la calle Alar del Rey. La desconcertante arquitectura del inmueble propiciâ”śâ”‚ que haya pasado a la memoria de la ciudad con una panoplia de fantâ”śĂ­sticas denominaciones: "Casa o Mansiâ”śâ”‚n de las Hadas", "Casa de las Brujas"..., seguramente por el extravagante remate del torreoncillo de la izquierda. Pocos aâ”śâ–’os despuâ”śÂ®s, tras el cese de actividad educativa, esta simpar construcciâ”śâ”‚n fue derribada, y sobre el solar resultante se levantâ”śâ”‚ el actual Colegio Mayor Peâ”śâ–’alba, con capacidad para 62 residentes numerarias femeninas del Opus Dei (por aâ”śâ–’o acadâ”śÂ®mico). Al fondo a la izquierda, los bloques de los nâ”śâ•‘meros 11-13 y 15 de la calle de Zumalacâ”śĂ­rregui, que aâ”śâ•‘n existen. El resto de edificios han sido sustituidos por otros nuevos, modernos.', 1969, 1969, 1969, 'Anos 60', 'UNIVERSIDAD', 41.64301300, -0.88693200, '0101000020E6100000F2D3B837BF61ECBF91F3FE3F4ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14652008628.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14652008628.webp', 'https://www.flickr.com/photos/zaragozaantigua/14652008628/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23482, 'Calle de Gil de Jasa c.1960', 'Imagen parcial de la antigua "Villa Teresa", singular casa de postâ”śÂˇn esquinera entre las calles de Gil de Jasa y de la Cadena (luego Alar del Rey) y construida en bizarras formas neogâ”śâ”‚ticas en los albores del siglo XX, cuando aâ”śâ•‘n no era obligatorio presentar proyecto de obra ni planos ante el Ayuntamiento. Por ello, esta es una de las pocas referencias visuales de que este edificio fue una realidad, no una ensoâ”śâ–’aciâ”śâ”‚n. En el momento de capturar esta fotografâ”śÂˇa la casa, propiedad de la familia Delgado Yarza, llevaba poco tiempo alquilada como sede del colegio femenino de bachillerado "Santo Tomâ”śĂ­s de Aquino", sito en la calle Gil de Jasa nâ”¬â•‘ 24. La desconcertante arquitectura neomedieval del inmueble propiciâ”śâ”‚ que haya pasado a la memoria de la ciudad con una panoplia de fantâ”śĂ­sticas y/o româ”śĂ­nticas denominaciones: "Casa o Mansiâ”śâ”‚n de las Hadas", "Casa de las Brujas"..., seguramente por el extravagante chapitel que remata el torreoncillo de la izquierda, que en esta imagen no llega a verse en su integridad. A principios de la prodigiosa (en tâ”śÂ®rminos urbanâ”śÂˇsticos) dâ”śÂ®cada de los aâ”śâ–’os setenta, poco despuâ”śÂ®s del cese de actividad educativa, esta simpar construcciâ”śâ”‚n fue derribada. Fuente visual: www.rafaelcastillejo.com/', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.64294800, -0.88697900, '0101000020E61000001EA4A7C82162ECBFA983BC1E4CD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44478146955.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44478146955.webp', 'https://www.flickr.com/photos/zaragozaantigua/44478146955/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23484, 'Calle de Gil de Jasa 1960', 'Dibujo representando la singular estampa de la antigua "Villa Teresa" construida en bizarras formas neogâ”śâ”‚ticas en los albores del siglo XX, y con ingreso principal por la calle de Gil de Jasa, en primer tâ”śÂ®rmino. A la izquierda, la calle de Alar del Rey. La casa, propiedad de la familia Delgado Yarza, estaba reciâ”śÂ®n alquilada para acoger el bachillerato femenino del colegio Santo Tomâ”śĂ­s de Aquino, y asâ”śÂˇ serâ”śÂˇa hasta el principio de la dâ”śÂ®cada siguiente, cuando este colegio fue trasladado a unas nuevas instalaciones en la calle del Maestro Estremiana nâ”¬â•‘ 48. Fuente visual: "Grabado en la mente. Historia del Colegio Santo Tomaâ• ĂĽs Aquino de Zaragoza", Santiago Sancho Vallestâ”śÂˇn.', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.64294800, -0.88697900, '0101000020E61000001EA4A7C82162ECBFA983BC1E4CD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44859897284.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44859897284.webp', 'https://www.flickr.com/photos/zaragozaantigua/44859897284/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23485, 'P.â”¬â•‘ de Ruiseâ”śâ–’ores 1928', 'Imagen de la fachada principal de la nueva y singular casa de Josâ”śÂ® Solâ”śĂ­ proyectada por Regino Borobio y construida en el arranque del paseo de Ruiseâ”śâ–’ores, desde donde se ha capturado la fotografâ”śÂˇa. Sus formas entre racionalistas y regionalistas definen un edificio de tres alturas y planta en ele, con amplia zona de huerto y estanque en las traseras lindando con el inmediato parque de Pignatelli cuando por su interior todavâ”śÂˇa circulaba la tranviaria lâ”śÂˇnea de Torrero. En 1959 esta casa fue reformada por el propio Regino Borobio por encargo de las Religiosas Mercedarias Misioneras para convertirlo en la nueva sede del Colegio de Nuestra Seâ”śâ–’ora de la Merced (dejando asâ”śÂˇ su hasta entonces domicilio en la calle Moncayo del barrio de Cariâ”śâ–’ena), hasta hoy. En los aâ”śâ–’os setenta fue construida una moderna ampliaciâ”śâ”‚n edilicia del colegio sobre buena parte de la antigua zona de huerto y estanque traseros. Fuente visual: Archivo Borobio, en Mâ”śâ”‚nica Vâ”śĂ­zquez Astorga, "Recorrido por el pasado de una zona urbana residencial: el paseo de Ruiseâ”śâ–’ores de Zaragoza".', 1928, 1928, 1928, 'Anos 20', 'UNIVERSIDAD', 41.63817200, -0.88656500, '0101000020E610000058E71890BD5EECBF889CBE9EAFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45264183611.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45264183611.webp', 'https://www.flickr.com/photos/zaragozaantigua/45264183611/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24008, 'Colegio Alemâ”śĂ­n 1937', '"Un aspecto de la patriâ”śâ”‚tica fiesta celebrada en el Colegio Alemâ”śĂ­n, con motivo del 48â”¬â•‘ aniversario del nacimiento del Canciller alemâ”śĂ­n Hitler". El Colegio Alemâ”śĂ­n estaba situado en la calle de Cervantes, y albergaba una colonia nazi que prestâ”śâ”‚ sus servicios al bando fascista local, usurpadores de la democracia entre 1936 y 1977. En el centro de la foto, retrato de Adolf Hitler. Fuente: Revista Aragâ”śâ”‚n, mayo de 1937.', 1937, 1937, 1937, 'Anos 30', 'UNIVERSIDAD', 41.64397500, -0.88708100, '0101000020E61000002EE57CB1F762ECBF8638D6C56DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23976258180.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23976258180.webp', 'https://www.flickr.com/photos/zaragozaantigua/23976258180/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24107, 'Calle de Cervantes, c.1942', 'Imagen capturada durante un homenaje a la bandera nacionalsocialista alemana realizado en el patio del Colegio Alemâ”śĂ­n sito en la calle de Miguel de Cervantes nâ”¬â•‘ 9. La derrota militar en mayo de 1945 del râ”śÂ®gimen nazi provocâ”śâ”‚, entre otras consecuencias, el cierre de los colegios alemanes en el extranjero. El de Zaragoza serâ”śÂˇa reabierto en 1956, muy distinto del de la fotografâ”śÂˇa.', 1942, 1942, 1942, 'Anos 40', 'UNIVERSIDAD', 41.64398300, -0.88742400, '0101000020E6100000A6EF3504C765ECBF0917F2086ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51789271991.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51789271991.webp', 'https://www.flickr.com/photos/zaragozaantigua/51789271991/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24179, 'Avenida de Goya c.1962', 'Cubrimiento de la zanja del ferrocarril en el tramo entre el paseo del General Mola, desde donde estâ”śĂ­ capturada la escena, y el paseo de Fernando el Catâ”śâ”‚lico. A la izquierda, el hotelito de los Palomar, luego derribado. A su lado, arbolado espacio junto a la iglesia del Perpetuo Socorro. Al fondo, insâ”śâ”‚lita vista de la chaflanera esquina del original taller de hierro forjado de Pascual Gonzâ”śĂ­lez, luego derribado, a la entrada del camino del Sâ”śĂ­bado. A la derecha, e inmediata, la academia de La Figuera, luego derribada.', 1962, 1962, 1962, 'Anos 60', 'UNIVERSIDAD', 41.64236500, -0.88654400, '0101000020E61000007AE1CE85915EECBF2A8C2D0439D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15428838548.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15428838548.webp', 'https://www.flickr.com/photos/zaragozaantigua/15428838548/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24186, 'Calle del Tenor Fleta 1951', 'Imagen de la calle del Tenor Fleta en su tramo cercano a General Mola, hacia donde se dirige la mirada. La trinchera del ferrocarril sin cubrir ha sido capturada desde uno de los puentes sobre las vâ”śÂˇas. Al fondo, el puente que salvaba el Paseo de Mola, y detrâ”śĂ­s, el inmueble esquinero del paseo del General Mola con la avenida de Goya, que fue colegio de las Carmelitas de la Caridad entre 1925 y 1949 y luego academia La Figuera hasta 1971. Habâ”śÂˇa sido levantada sobre los terrenos de la fâ”śĂ­brica de râ”śâ”‚tulos esmaltados Viâ”śâ–’ado, sita allâ”śÂˇ entre 1902 y 1925. Fuente visual: Juan Mora Insa, AMZ.', 1951, 1951, 1951, 'Anos 50', 'UNIVERSIDAD', 41.64209800, -0.88595500, '0101000020E61000002849D74CBE59ECBFDB696B4430D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20131601148.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20131601148.webp', 'https://www.flickr.com/photos/zaragozaantigua/20131601148/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24462, 'Fâ”śĂ­brica de calzado 1924', 'Fâ”śĂ­brica de calzado de Josâ”śÂ® Sorrosal, 1924. En 1916, Josâ”śÂ® Sorrosal trasladâ”śâ”‚ su fâ”śĂ­brica de zapatos al Camino del Sâ”śĂ­bado 1, esquina con la calle Benavente (foto). En 1926 la fâ”śĂ­brica cambiâ”śâ”‚ de dueâ”śâ–’o, pasando a ser Matâ”śÂˇas Peyrona. Asâ”śÂˇ, tambiâ”śÂ®n dejaron de comercializarse los Calzados Sorrosal en la tienda de Coso 24. El torreâ”śâ”‚n de la izquierda estaba dedicado a vivienda del propietario. Fuente: Mâ”¬Â¬ Pilar Biel Ibâ”śĂ­â”śâ–’ez, Zaragoza y la industrializaciâ”śâ”‚n: la arquitectura industrial 1875-1936, IFC, 2004.', 1924, 1924, 1924, 'Anos 20', 'UNIVERSIDAD', 41.64293200, -0.88835800, '0101000020E61000009E7AA4C16D6DECBFA4C684984BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19780485706.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19780485706.webp', 'https://www.flickr.com/photos/zaragozaantigua/19780485706/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24486, 'Fâ”śĂ­brica de calzado 1934', 'Fâ”śĂ­brica de calzado instalada en 1916 entre el Camino del Sâ”śĂ­bado y la calle Benavente. Desde 1926, propiedad de Matâ”śÂˇas Peyrona. Vemos el edificio desde la la calle del ferrocarril a Barcelona (actual avenida de Goya) con la calle del Camino del Sâ”śĂ­bado (actual Arzobispo Domenech), y la de Benavente, a la izquierda. Al fondo a la derecha, el râ”śÂˇo Huerva. Fuente: www.todocoleccon.net', 1934, 1934, 1934, 'Anos 30', 'UNIVERSIDAD', 41.64293200, -0.88835800, '0101000020E61000009E7AA4C16D6DECBFA4C684984BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24300027703.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24300027703.webp', 'https://www.flickr.com/photos/zaragozaantigua/24300027703/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24522, 'P.â”¬â•‘ de Torrero 1899', 'Dibujo de la antigua fâ”śĂ­brica de harinas de Almech ya reconvertida como fâ”śĂ­brica "La Pilar" de la Sociedad Espaâ”śâ–’ola del Acumulador Tudor, ubicada en el paseo de Torrero en la estratâ”śÂ®gica ubicaciâ”śâ”‚n entre el camino de las Torres (izquierda) y el camino de las Alcachoferas (derecha). En primer tâ”śÂ®rmino, una unidad de la tranviaria de tracciâ”śâ”‚n animal en servicio en lâ”śÂˇnea de Torrero, en descenso hacia la plaza de la Constituciâ”śâ”‚n. A la derecha, la caudalosa acequia de las Adulas o de San Josâ”śÂ® que abastecâ”śÂˇa de agua y energâ”śÂˇa a la fâ”śĂ­brica. La vecina torre de Forniâ”śÂ®s, al fondo, aâ”śâ–’os despuâ”śÂ®s se acumularâ”śÂˇa al perâ”śÂˇmetro industrial de esta destacable empresa durante una de las notables expansiones. Fuente visual: Hauser y Menet, en Universidad de Sevilla', 1899, 1899, 1899, 'Siglo XIX', 'UNIVERSIDAD', 41.63940900, -0.88593500, '0101000020E610000061376C5B9459ECBF50E27327D8D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39498948395.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39498948395.webp', 'https://www.flickr.com/photos/zaragozaantigua/39498948395/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24876, 'Casa de la Paz aâ”śâ–’os 80', 'Paseo de Sagasta 52. En 1987, colectivos de okupaciâ”śâ”‚n de Zaragoza reutilizaron el edificio. Era un chalâ”śÂ® de arquitectura eclâ”śÂ®ctica, construido en 1919 y abandonado en 1961. Fue desalojado en 1993 y derribado posteriormente. Hoy ocupa el solar un centro de salud. Mâ”śĂ­s informaciâ”śâ”‚n: www.zaragozarebelde.org/una-vision-parcial-de-la-ocupacio...', 1980, 1980, 1989, 'Anos 80', 'UNIVERSIDAD', 41.64169800, -0.88655000, '0101000020E6100000029A081B9E5EECBF4DF4F92823D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14761552780.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14761552780.webp', 'https://www.flickr.com/photos/zaragozaantigua/14761552780/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24884, 'Casa de la Paz c.1989', 'Paseo de Sagasta 52. En 1987, colectivos de okupaciâ”śâ”‚n de Zaragoza reutilizaron el edificio. Era un chalâ”śÂ® de arquitectura eclâ”śÂ®ctica, construido en 1919 y abandonado en 1961. Fue desalojado en 1993 y derribado posteriormente. Hoy ocupa el solar un centro de salud. Mâ”śĂ­s informaciâ”śâ”‚n: www.zaragozarebelde.org/una-vision-parcial-de-la-ocupacio...', 1989, 1989, 1989, 'Anos 80', 'UNIVERSIDAD', 41.64172000, -0.88652200, '0101000020E610000086E7A562635EECBF359886E123D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14916167836.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14916167836.webp', 'https://www.flickr.com/photos/zaragozaantigua/14916167836/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24886, 'P.â”¬â•‘ de Sagasta 1925', 'Archivo Mora. "Casa Faci", encargo de â”śĂĽngel Faci a Regino Borobio, en su localizaciâ”śâ”‚n del Paseo de Sagasta, chaflâ”śĂ­n con el inicio de Camino de las Torres. La notorieda de este edificio, en el que se entroncan las corrientes estilâ”śÂˇsticas antiguas y modernas, no pasâ”śâ”‚ desapercida, y fue reseâ”śâ–’ado en la madrileâ”śâ–’a revista "Arquitectura" (nâ”śâ•‘m. 98, 1927). Pero las cosas son como son, y serâ”śĂ­ derribada en 1971 para dar paso a un bloque de viviendas mâ”śĂ­s aprovechadico en lo vertical.', 1925, 1925, 1925, 'Anos 20', 'UNIVERSIDAD', 41.64011800, -0.88620700, '0101000020E61000008A8F4FC8CE5BECBF5CCAF962EFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14930631405.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14930631405.webp', 'https://www.flickr.com/photos/zaragozaantigua/14930631405/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24902, 'P.â”¬â•‘ del General Mola c.1973', 'Foto: Gonzalo Borrâ”śĂ­s. Fachada de la desaparecida residencia modernista de Pedro Marcolaâ”śÂˇn, en el paseo de Sagasta nâ”¬â•‘ 20 tripl. Proyectada por Josâ”śÂ® Graner Prat en 1903. Derribada poco despuâ”śÂ®s de esta captura fotogrâ”śĂ­fica, su lugar lo ocupa hoy la mole de nueve alturas de los nâ”śâ•‘meros 32 al 38, previo piqueteo de este hotelito y sus inmediatos vecinos. Fuente visual: "La modernidad y la Exposiciâ”śâ”‚n Hispano Francesa de Zaragoza en 1908", Universidad de Zaragoza, 2004.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.64365200, -0.88622200, '0101000020E6100000DFDC5F3DEE5BECBFA400513063D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15535230465.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15535230465.webp', 'https://www.flickr.com/photos/zaragozaantigua/15535230465/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24907, 'P.â”¬â•‘ del General Mola 1976', 'Aspecto parcial de la casa de Emerenciano Garcâ”śÂˇa, ejemplo del modernismo zaragozano y obra de Manuel martâ”śÂˇnez de Ubago de 1909. Fue derribada en 1976. Al fondo, el nâ”śâ•‘mero 56, mostrando el retranqueo de la casa fotografiada, que ocupaba el 54 del paseo del General Mola. Fuente: foto Gonzalo Borrâ”śĂ­s, en Zaragoza a principios del s. XX: el modernismo. Librerâ”śÂˇa General, 1977.', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.64136900, -0.88637300, '0101000020E610000049D6E1E82A5DECBF88D51F6118D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19406597966.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19406597966.webp', 'https://www.flickr.com/photos/zaragozaantigua/19406597966/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24999, 'Acequia de San Josâ”śÂ® 1925', 'Desde el Canal Imperial de Aragâ”śâ”‚n y a travâ”śÂ®s del Parque de Buenavista, bajaba por gravedad la acequia de las Adulas, tambiâ”śÂ®n llamada de San Josâ”śÂ® por el antiguo y referencial convento, luego penal y finalmente cuartel. En este tramo fluâ”śÂˇa al aire y en sinuoso paralelo al paseo de los Ruiseâ”śâ–’ores, y cruzaba (soterrada) el paseo de Sagasta para luego seguir su recorrido nuevamente al aire por el camino de las Torres tras surtir a la fâ”śĂ­brica La Pilar de la Tudor. La imagen se habrâ”śÂˇa capturado justo desde el principio del paseo de los Ruiseâ”śâ–’ores, junto al transformador elâ”śÂ®ctrico sobre la acequia, en una despejada zona que en los aâ”śâ–’os treinta serâ”śÂˇa urbanizada como zona verde, eliminando el edificio de "Las tres BBB", y colocando isletas de jardâ”śÂˇn y arbustos. Al fondo, construcciones de la antigua casa de Victoriano Zorraquino. A su lado, y sobre el cauce de la acequia, la pasarela que conectaba la calle de Sevilla con el paseo de Ruiseâ”śâ–’ores.', 1925, 1925, 1925, 'Anos 20', 'UNIVERSIDAD', 41.63881900, -0.88638400, '0101000020E6100000435376FA415DECBF1E882CD2C4D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14943152450.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14943152450.webp', 'https://www.flickr.com/photos/zaragozaantigua/14943152450/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25005, 'P.â”¬â•‘ de Ruiseâ”śâ–’ores 1930', '"Vista de la subida de coches y estancia" del "Restaurant Ruiseâ”śâ–’ores" de Zaragoza, tarjeta postal editada por "Huecograbado Mumbrâ”śâ•‘ S.C. Barcelona". En 1930, el arquitecto Marcelino Securun Orga diseâ”śâ–’â”śâ”‚ el "Restaurante de verano de Francisco Gargallo", localizado al principio del paseo de Ruiseâ”śâ–’ores. En la imagen, empinado acceso rodado desde el paseo, que queda a la izquierda, donde se encontraba la entrada principal. Este lugar, al principio de los aâ”śâ–’os 30 del pasado siglo, quedaba bastante lejos de lo que entonces se consideraba ciudad. A la derecha, muros perimetrales de los extensos depâ”śâ”‚sitos de agua lindantes con la avenida de Wilson y los jardines de Pignatelli, el destino final del monumento al ilustrado prâ”śâ”‚cer tras su destierro de la plaza de Aragâ”śâ”‚n. A la izquierda, fuera de plano, aunque inmediata, la galerâ”śÂˇa y traseras de la "casa del Poeta", sufragada por la ciudad para el renombrado bardo Alberto Casaâ”śâ–’al Shakery, entonces en construcciâ”śâ”‚n. Este "restaurant", que incluâ”śÂˇa una concurrida pista de baile, y que era lugar de moda para comidas y cenas de posibles, a los pocos aâ”śâ–’os fue clausurado, y las construcciones de la imagen quedaron abandonadas y en ruinas, hasta que al comienzo de los aâ”śâ–’os 50 este entorno fue nuevamente edificado, ahora con viviendas. La dura cuesta de acceso ha sido cerrada con verja, pues forma parte del privado espacio edilicio al que se accede desde la actual calle de Santiago Guallar. Fuente visual: www.todocoleccion.net/', 1930, 1930, 1930, 'Anos 30', 'UNIVERSIDAD', 41.63690500, -0.88806700, '0101000020E6100000C504357C0B6BECBF56D4601A86D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24594386414.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24594386414.webp', 'https://www.flickr.com/photos/zaragozaantigua/24594386414/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25007, 'Escuelas de Torrero 1885', 'En el bienio 1884-85 fueron creadas en la ciudad varias escuelas pâ”śâ•‘blicas, sobre todo en barrios rurales y zonas de la periferia entre las que se encontraba Torrero, denominaciâ”śâ”‚n que incluâ”śÂˇa unas cuantas terrazas por debajo del Canal Imperial, y buena parte del camino de Torrero, luego paseo de Sagasta. Asâ”śÂˇ, en el paseo de Cuâ”śÂ®llar, entre los depâ”śâ”‚sitos de agua y el cauce al aire de la nueva acequia del Plano derivada del Canal, fue construido un edificio de 680 m2 con capacidad para unos 100 niâ”śâ–’os, en materiales muy econâ”śâ”‚micos: adobe y mamposterâ”śÂˇa, y ladrillo en las zonas estructurales. La escuela se encontraba en la planta calle, y la planta superior se habilitâ”śâ”‚ para vivienda del maestro, plaza que fue ocupada por Marcelino Lâ”śâ”‚pez Ornat, posiblemente quien aparece en la fotografâ”śÂˇa, rodeado de la abundante tropilla colegial, en un grupal posado donde las traseras de la escuela. Fue la existencia de esta instalaciâ”śâ”‚n educativa la que determinâ”śâ”‚ que el nuevo vial luego abierto para conectar con el paseo de Ruiseâ”śâ–’ores fuera denominado, precisamente, calle de las Escuelas. Mâ”śĂ­s tarde serâ”śÂˇa redenominado Maestro Estremiana como homenaje a Pablo Estremiana, que trabajâ”śâ”‚ aquâ”śÂˇ de maestro en la segunda y tercera dâ”śÂ®cadas del siglo XX. Fuente visual: Foto Estudio Coyne, AHPZ.', 1885, 1885, 1885, 'Siglo XIX', 'UNIVERSIDAD', 41.63564600, -0.88552400, '0101000020E6100000DE567A6D3656ECBFA7EA1ED95CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30829414034.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30829414034.webp', 'https://www.flickr.com/photos/zaragozaantigua/30829414034/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25016, 'Casa Juncosa c.1909', 'Archivo y Hemeroteca Municipales de Zaragoza, entre 1906 y 1910. Vivienda modernista de Julio Juncosa en el paseo de Sagasta 11, proyectada por Josâ”śÂ® de Yarza en colaboraciâ”śâ”‚n con Ricardo Magdalena en 1903 y concluida en 1906. Sobrevive. Fuente visual: "Ricardo Magdalena. Arquitecto municipal de Zaragoza", IFC, 2012.', 1909, 1909, 1909, 'Anos 1900', 'UNIVERSIDAD', 41.64342300, -0.88583000, '0101000020E61000000D1AFA27B858ECBF423F53AF5BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14920526584.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14920526584.webp', 'https://www.flickr.com/photos/zaragozaantigua/14920526584/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25000, 'P.â”¬â•‘ de Ruiseâ”śâ–’ores 1922', 'El burguâ”śÂ®s ensanche de Sagasta tenâ”śÂˇa un brazo que se extendâ”śÂˇa por el paseo de Ruiseâ”śâ–’ores, con notables muestras de viviendas unifamiliares u hotelitos historicistas, modernistas, e incluso alguna rareza del racionalismo de vanguardia. En la imagen, insâ”śâ”‚lita vista del nâ”¬â•‘ 24, novâ”śÂˇsima casa de Victoriano Carbonâ”śÂ® como segunda residencia de este prâ”śâ”‚cer local, presidente de la Uniâ”śâ”‚n Ultramarina de Dependientes de Zaragoza, y concejal. Fue proyectada por Francisco Albiâ”śâ–’ana Corralâ”śÂ® pocos aâ”śâ–’os antes. A la izquierda, puerta de ingreso al Colegio Pompiliano de las Madres Escolapias, en el nâ”¬â•‘ 26. A ambos lados del terroso paseo, pequeâ”śâ–’os riegos para canalizar el agua, entubados en los accesos a las viviendas. Fuente visual: Archivo Fotogrâ”śĂ­fico Julio Requejo, en AHPZ.', 1922, 1922, 1922, 'Anos 20', 'UNIVERSIDAD', 41.63649400, -0.88940900, '0101000020E6100000FB93F8DC0976ECBFD40CA9A278D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15129204712.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15129204712.webp', 'https://www.flickr.com/photos/zaragozaantigua/15129204712/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25017, 'P.â”¬â•‘ del General Mola 1978', 'Este "hotelito" del Paseo de Sagasta fue construido en 1919 por Teodoro Râ”śÂˇos para Luis Lâ”śâ”‚pez, en la parcela del nâ”¬â•‘ 24 dpdo. (luego nâ”¬â•‘ 52), justo al lado del impresionante hotelito de Emerenciano Garcâ”śÂˇa (izquierda, fuera de plano). Las posteriores vicisitudes de este hotelito forman parte de la reciente historia de los movimientos sociales de la ciudad: abandonado desde 1950, en marzo de 1987 el edificio fue ocupado como "Casa de la Paz y la Solidaridad", sede del feminismo, antimilitarismo, ecologismo, anticapitalismo, antisistemismo, desde una perspectiva radical. En diciembre de 1993, tras seis intensos aâ”śâ–’os de activismo, con sus luces y sombras, miserias y grandezas, la casa fue desalojada. Luego fue derribada, y su propietario (el INSALUD), levantâ”śâ”‚ el actual Centro de Salud Josâ”śÂ® Ramâ”śâ”‚n Muâ”śâ–’oz Fernâ”śĂ­ndez. Su eclâ”śÂ®ctica arquitectura presentaba 540 m2 â”śâ•‘tiles de vivienda, repartidos entre un semisâ”śâ”‚tano, dos plantas, y un â”śĂ­tico, y mas de 150m2 de jardâ”śÂˇn (incluyendo un gallinero). Hasta su derribo, fue el â”śâ•‘ltimo de los hotelitos del burguâ”śÂ®s Paseo de Sagasta. Queda y perdura en la memoria de toda la gente que pasâ”śâ”‚ por â”śÂ®l. En la captura, imagen del nâ”¬â•‘ 52 del Paseo Sagasta, abandonado y aprisionado entre el moderno bloque del nâ”¬â•‘ 50, a la derecha (reciâ”śÂ®n inaugurado), y el bloque del nâ”¬â•‘ 54, a la izquierda y fuera de plano, tambiâ”śÂ®n de nueva factura. Fuente visual: "La evoluciâ”śâ”‚n urbana de Zaragoza al este del Huerva", Carmen Santos Vich, 1978.', 1978, 1978, 1978, 'Anos 70', 'UNIVERSIDAD', 41.64169800, -0.88655000, '0101000020E6100000029A081B9E5EECBF4DF4F92823D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14922703769.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14922703769.webp', 'https://www.flickr.com/photos/zaragozaantigua/14922703769/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25021, 'P.â”¬â•‘ de Sagasta 1906', 'Fâ”śĂ­brica de hierro esmaltado Viâ”śâ–’ado y Burbano. 1906 Manuel Viâ”śâ–’ado montâ”śâ”‚ en 1890, en la calle Cinco de Marzo nâ”¬â•‘ 4, una fâ”śĂ­brica de râ”śâ”‚tulos esmaltados. En 1902 se trasladâ”śâ”‚, por ampliaciâ”śâ”‚n de negocio, al Paseo de Sagasta nâ”¬â•‘ 22 (duplicado), a una manzana delimitada por un breve frontal al Paseo de Sagasta, y dos largas fachadas, una al Camino de la Cadena (luego, Alar del Rey), y otra a la trinchera del ferrocarril MZA (mucho mâ”śĂ­s tarde, Avenida de Goya). La nueva factorâ”śÂˇa fue diseâ”śâ–’ada por Julio Bravo, e incluâ”śÂˇa una vivienda, ademâ”śĂ­s de la fâ”śĂ­brica y almacenes. En 1925, con la denominaciâ”śâ”‚n "Viâ”śâ–’ado Hermanos", la fâ”śĂ­brica fue desmantelada, y trasladada al camino del Terminillo. Ese aâ”śâ–’o se abriâ”śâ”‚ en este lugar el Colegio de las Hermanas Carmelitas de la Caridad, hasta el 1949, en que se reubicaron en su actual sede de Madre Vedruna-Leâ”śâ”‚n XIII. Luego se instalâ”śâ”‚ luego la Academia preparatoria de acceso a la AGM "La Figuera", hasta 1971, en que se trasladan a Cantâ”śÂˇn y Gamboa. La imagen se corresponde con un anuncio publicado en "Zaragoza, Guâ”śÂˇa del Viajero. Aâ”śâ–’o 1906", de Josâ”śÂ® Marâ”śÂˇa Casi. La fotografâ”śÂˇa estâ”śĂ­ tomada desde el paseo de Sagasta.', 1906, 1906, 1906, 'Anos 1900', 'UNIVERSIDAD', 41.64264000, -0.88673500, '0101000020E610000072FE26142260ECBFFC8C0B0742D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15436979227.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15436979227.webp', 'https://www.flickr.com/photos/zaragozaantigua/15436979227/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25022, 'Verkos 1940', 'Imagen de los Laboratorios Verkos, instalados desde 1938 en este edificio en la calle Gil de Jasa nâ”¬â•‘ 16, esquina con calle Cervantes, donde la Farmacia de los Laboratorios tenâ”śÂˇa su entrada propia en el nâ”¬â•‘ 3 de esa calle. En 1976 abandonaron estas instalaciones, y se trasladaron a su actual ubicaciâ”śâ”‚n, en la carretera de Logroâ”śâ–’o, km. 20, al lado de Pinseque. En 1979 la piqueta derribâ”śâ”‚ el inmueble, y en su solar se levantaron las actuales viviendas. Una moderna farmacia fue habilitada donde estuviera la antigua. Fuente visual: Foto Gabriel Casas i Galobardes para Laboratorios Verkos, en Arxiu Nacional de Catalunya.', 1940, 1940, 1940, 'Anos 40', 'UNIVERSIDAD', 41.64395000, -0.88680200, '0101000020E610000065E08096AE60ECBF2D211FF46CD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15509220684.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15509220684.webp', 'https://www.flickr.com/photos/zaragozaantigua/15509220684/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
